#!/usr/bin/env node

const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

// Configuration
const CONFIG = {
  nodeVersion: process.env.NODE_VERSION || '18',
  testTimeout: process.env.TEST_TIMEOUT || '300000',
  buildDir: process.env.BUILD_DIR || 'dist',
  deployTarget: process.env.DEPLOY_TARGET || 'production',
  sbomFormat: 'cyclonedx',
  sbomOutput: 'sbom.json'
};

// Logging utility
function log(message, level = 'INFO') {
  const timestamp = new Date().toISOString();
  console.log(`[${timestamp}] [${level}] ${message}`);
}

// Execute command with error handling
function execCommand(command, options = {}) {
  try {
    log(`Executing: ${command}`);
    const output = execSync(command, {
      stdio: 'inherit',
      encoding: 'utf-8',
      ...options
    });
    return output;
  } catch (error) {
    log(`Command failed: ${command}`, 'ERROR');
    log(`Error: ${error.message}`, 'ERROR');
    process.exit(1);
  }
}

// Generate SBOM (Software Bill of Materials)
function generateSBOM() {
  log('Generating Software Bill of Materials (SBOM)...');
  
  // Install SBOM generator if not present
  try {
    execSync('which cyclonedx-npm', { stdio: 'ignore' });
  } catch {
    log('Installing CycloneDX SBOM generator...');
    execCommand('npm install -g @cyclonedx/cyclonedx-npm');
  }
  
  // Generate SBOM
  execCommand(`cyclonedx-npm --output-file ${CONFIG.sbomOutput} --output-format JSON`);
  
  // Verify SBOM was created
  if (!fs.existsSync(CONFIG.sbomOutput)) {
    log('SBOM generation failed', 'ERROR');
    process.exit(1);
  }
  
  log(`SBOM generated successfully: ${CONFIG.sbomOutput}`);
  
  // Generate SBOM hash for integrity verification
  const sbomContent = fs.readFileSync(CONFIG.sbomOutput);
  const sbomHash = crypto.createHash('sha256').update(sbomContent).digest('hex');
  fs.writeFileSync(`${CONFIG.sbomOutput}.sha256`, sbomHash);
  log(`SBOM SHA256: ${sbomHash}`);
  
  return CONFIG.sbomOutput;
}

// Verify dependencies against SBOM
function verifyDependencies() {
  log('Verifying dependencies against SBOM...');
  
  if (!fs.existsSync(CONFIG.sbomOutput)) {
    log('SBOM not found, skipping verification', 'WARN');
    return;
  }
  
  const sbom = JSON.parse(fs.readFileSync(CONFIG.sbomOutput, 'utf-8'));
  const componentCount = sbom.components ? sbom.components.length : 0;
  log(`SBOM contains ${componentCount} components`);
  
  // Verify package-lock.json exists for reproducible builds
  if (!fs.existsSync('package-lock.json')) {
    log('package-lock.json not found - builds may not be reproducible', 'WARN');
  }
}

// Audit dependencies for vulnerabilities
function auditDependencies() {
  log('Auditing dependencies for security vulnerabilities...');
  
  try {
    execCommand('npm audit --audit-level=high --production');
  } catch (error) {
    log('Security vulnerabilities found in dependencies', 'ERROR');
    log('Please review and fix vulnerabilities before deploying', 'ERROR');
    process.exit(1);
  }
  
  log('Dependency audit passed');
}

// Install dependencies
function installDependencies() {
  log('Installing dependencies...');
  
  // Use ci for faster, reproducible installs
  if (fs.existsSync('package-lock.json')) {
    execCommand('npm ci --prefer-offline --no-audit');
  } else {
    log('package-lock.json not found, using npm install', 'WARN');
    execCommand('npm install --prefer-offline');
  }
  
  log('Dependencies installed successfully');
}

// Run tests
function runTests() {
  log('Running tests...');
  
  execCommand(`npm test -- --maxWorkers=50%`, {
    env: { ...process.env, NODE_ENV: 'test', TEST_TIMEOUT: CONFIG.testTimeout }
  });
  
  log('All tests passed');
}

// Build application
function buildApplication() {
  log('Building application...');
  
  execCommand('npm run build', {
    env: { ...process.env, NODE_ENV: 'production' }
  });
  
  // Verify build output
  if (!fs.existsSync(CONFIG.buildDir)) {
    log(`Build directory ${CONFIG.buildDir} not found`, 'ERROR');
    process.exit(1);
  }
  
  log('Application built successfully');
}

// Generate deployment manifest with SBOM reference
function generateDeploymentManifest() {
  log('Generating deployment manifest...');
  
  const manifest = {
    timestamp: new Date().toISOString(),
    version: process.env.npm_package_version || 'unknown',
    commit: process.env.CI_COMMIT_SHA || execSync('git rev-parse HEAD', { encoding: 'utf-8' }).trim(),
    branch: process.env.CI_COMMIT_BRANCH || execSync('git rev-parse --abbrev-ref HEAD', { encoding: 'utf-8' }).trim(),
    nodeVersion: process.version,
    sbom: {
      file: CONFIG.sbomOutput,
      hash: fs.readFileSync(`${CONFIG.sbomOutput}.sha256`, 'utf-8').trim(),
      format: CONFIG.sbomFormat
    },
    buildDir: CONFIG.buildDir,
    deployTarget: CONFIG.deployTarget
  };
  
  fs.writeFileSync('deployment-manifest.json', JSON.stringify(manifest, null, 2));
  log('Deployment manifest created');
  
  return manifest;
}

// Deploy application
function deployApplication(manifest) {
  log(`Deploying to ${CONFIG.deployTarget}...`);
  
  // Copy SBOM and manifest to build directory
  fs.copyFileSync(CONFIG.sbomOutput, path.join(CONFIG.buildDir, CONFIG.sbomOutput));
  fs.copyFileSync(`${CONFIG.sbomOutput}.sha256`, path.join(CONFIG.buildDir, `${CONFIG.sbomOutput}.sha256`));
  fs.copyFileSync('deployment-manifest.json', path.join(CONFIG.buildDir, 'deployment-manifest.json'));
  
  // Deploy based on target
  if (CONFIG.deployTarget === 'production') {
    log('Deploying to production environment...');
    // Add your production deployment logic here
    // Example: execCommand('rsync -avz dist/ user@production-server:/var/www/app/');
    // Example: execCommand('kubectl apply -f k8s/production/');
    log('Production deployment completed');
  } else {
    log(`Deploying to ${CONFIG.deployTarget} environment...`);
    // Add your staging/dev deployment logic here
    log(`${CONFIG.deployTarget} deployment completed`);
  }
  
  log('Deployment successful');
}

// Main pipeline execution
function main() {
  const startTime = Date.now();
  
  log('=== Starting CI/CD Pipeline ===');
  log(`Node.js version: ${process.version}`);
  log(`Deploy target: ${CONFIG.deployTarget}`);
  
  try {
    // Step 1: Install dependencies
    installDependencies();
    
    // Step 2: Generate SBOM
    generateSBOM();
    
    // Step 3: Verify dependencies
    verifyDependencies();
    
    // Step 4: Audit dependencies
    auditDependencies();
    
    // Step 5: Run tests
    runTests();
    
    // Step 6: Build application
    buildApplication();
    
    // Step 7: Generate deployment manifest
    const manifest = generateDeploymentManifest();
    
    // Step 8: Deploy application
    deployApplication(manifest);
    
    const duration = ((Date.now() - startTime) / 1000).toFixed(2);
    log(`=== Pipeline completed successfully in ${duration}s ===`);
    log(`SBOM available at: ${CONFIG.sbomOutput}`);
    log(`Deployment manifest: deployment-manifest.json`);
    
  } catch (error) {
    log('Pipeline failed', 'ERROR');
    log(error.message, 'ERROR');
    process.exit(1);
  }
}

// Run pipeline
if (require.main === module) {
  main();
}

module.exports = { main, generateSBOM, verifyDependencies, auditDependencies };